      CREATE OR REPLACE FUNCTION notify_hl7_appointment_booked()
RETURNS TRIGGER AS $function$
      BEGIN
      INSERT INTO ${hl7.integrationSchema}.hl7_event (
        id,
        event_type,
        object_key,
        event_datetime
      )
      VALUES (
               gen_random_uuid()::varchar,
               '${hl7.events.appointmentCreated}',
               NEW.id::varchar,
               NOW()
             );

      RETURN NEW;
      END;
      $function$ LANGUAGE plpgsql;


      DROP TRIGGER IF EXISTS trg_hl7_appointment_booked ON appointment;

      CREATE TRIGGER trg_hl7_appointment_booked
        AFTER UPDATE OF status ON appointment
        FOR EACH ROW
        WHEN (
        NEW.status = 'BOOKED'
        AND OLD.status IS DISTINCT FROM NEW.status
)
EXECUTE FUNCTION notify_hl7_appointment_booked();
